
'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { Bus, LogIn, Loader2, Eye, EyeOff } from "lucide-react";
import Link from 'next/link';
import { auth } from '@/lib/firebase';
import { signInWithEmailAndPassword } from 'firebase/auth';
import { getUserRole } from '@/services/users';

type UserRole = 'admin' | 'driver' | 'parent';

export default function LoginPage() {
  const router = useRouter();
  const { toast } = useToast();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [activeTab, setActiveTab] = useState<UserRole>('admin');

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email || !password) return;
    setIsLoading(true);

    try {
      // 1. Authenticate with Firebase
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const user = userCredential.user;

      if (user && user.email) {
        // 2. Verify the user's role from your database
        const userRole = await getUserRole(user.email);

        // 3. Check if the role matches the selected tab
        if (userRole === activeTab) {
          toast({
            title: "Login Successful",
            description: `Welcome! Redirecting to the ${activeTab} dashboard.`,
          });
          router.push(`/dashboard/${activeTab}`);
        } else {
          await auth.signOut(); // Log out the user if role is incorrect
          toast({
            variant: "destructive",
            title: "Login Failed",
            description: `You do not have permission to access the ${activeTab} dashboard.`,
          });
        }
      } else {
          throw new Error("Could not retrieve user information after login.");
      }
    } catch (error) {
      console.error(error);
      toast({
        variant: "destructive",
        title: "Login Failed",
        description: "Invalid email or password. Please try again.",
      });
    } finally {
        setIsLoading(false);
    }
  };
  
  const handleTabChange = (value: string) => {
      setActiveTab(value as UserRole);
      setEmail('');
      setPassword('');
      setShowPassword(false);
  }

  return (
    <div className="flex min-h-screen flex-col items-center justify-center bg-muted/40 p-4">
      <div className="absolute top-4 left-4 z-10 hidden md:flex">
        <div className="flex items-center justify-center gap-2">
            <Bus className="h-6 w-6 text-primary" />
            <span className="text-lg font-semibold font-headline">SafeRoute</span>
        </div>
      </div>

      <Card className="w-full max-w-sm z-10">
          <CardHeader className="text-center">
              <div className="mx-auto bg-primary/20 text-primary p-3 rounded-full w-fit mb-4">
                  <Bus className="h-8 w-8" />
              </div>
              <CardTitle className="text-2xl font-bold font-headline">Welcome to SafeRoute</CardTitle>
              <CardDescription>Sign in to your account.</CardDescription>
          </CardHeader>
          <CardContent>
             <div className="flex justify-around mb-6 border-b">
                 <button onClick={() => handleTabChange('admin')} className={`py-2 px-4 text-sm font-medium ${activeTab === 'admin' ? 'border-b-2 border-primary text-primary' : 'text-muted-foreground'}`}>Admin</button>
                 <button onClick={() => handleTabChange('driver')} className={`py-2 px-4 text-sm font-medium ${activeTab === 'driver' ? 'border-b-2 border-primary text-primary' : 'text-muted-foreground'}`}>Driver</button>
                 <button onClick={() => handleTabChange('parent')} className={`py-2 px-4 text-sm font-medium ${activeTab === 'parent' ? 'border-b-2 border-primary text-primary' : 'text-muted-foreground'}`}>Parent</button>
            </div>
            <form onSubmit={handleLogin} className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="email">Email</Label>
                <Input 
                  id="email" 
                  type="email" 
                  placeholder="m@example.com" 
                  required 
                  value={email} 
                  onChange={(e) => setEmail(e.target.value)} 
                  disabled={isLoading}
                />
              </div>
              <div className="space-y-2">
                <div className="flex items-center justify-between">
                  <Label htmlFor="password">Password</Label>
                  <Link
                      href="#"
                      className="text-sm font-medium text-primary hover:underline"
                  >
                      Forgot password?
                  </Link>
                </div>
                <div className="relative">
                  <Input 
                    id="password" 
                    type={showPassword ? "text" : "password"} 
                    required 
                    value={password} 
                    onChange={(e) => setPassword(e.target.value)} 
                    disabled={isLoading} 
                  />
                   <Button type="button" variant="ghost" size="icon" className="absolute top-0 right-0 h-full px-3 py-2 hover:bg-transparent" onClick={() => setShowPassword(prev => !prev)}>
                      {showPassword ? <EyeOff /> : <Eye />}
                      <span className="sr-only">{showPassword ? 'Hide password' : 'Show password'}</span>
                  </Button>
                </div>
              </div>
              <Button type="submit" className="w-full" disabled={isLoading || !email || !password}>
                {isLoading ? (
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                ) : (
                  <LogIn className="mr-2 h-4 w-4" />
                )}
                {isLoading ? 'Signing In...' : 'Sign In'}
              </Button>
            </form>
          </CardContent>
          <CardFooter>
               <p className="text-xs text-muted-foreground text-center w-full">
                  © 2025 SafeRoute. All rights reserved.
               </p>
          </CardFooter>
        </Card>
    </div>
  );
}
